<?php
namespace App\Http\Controllers\Api\Admin\Marketing;
use App\Http\Controllers\Concerns\ApiResponses; use App\Http\Controllers\Controller; use App\Services\Marketing\CustomerSegmentationService; use Illuminate\Http\JsonResponse; use Illuminate\Http\Request; use Illuminate\Support\Facades\DB; use Illuminate\Support\Str;
class CrmController extends Controller { use ApiResponses; public function customers(Request $r): JsonResponse { return $this->success(DB::table('customer_profiles')->orderByDesc('id')->paginate((int)$r->query('per_page',25))); } public function customer(int $id): JsonResponse { return $this->success(DB::table('customer_profiles')->find($id)); } public function segments(): JsonResponse { return $this->success(DB::table('customer_segments')->orderBy('name')->get()); } public function storeSegment(Request $r, CustomerSegmentationService $s): JsonResponse { $d=$r->validate(['name'=>'required|string|max:190','description'=>'nullable|string','rules'=>'array','type'=>'nullable|string|max:40','is_active'=>'boolean']); return $this->success(['id'=>$s->create($d)],201); } public function refreshSegment(int $id, CustomerSegmentationService $s): JsonResponse { return $this->success(['matched'=>$s->refresh($id)]); } public function contactLists(): JsonResponse { return $this->success(DB::table('contact_lists')->orderBy('name')->get()); } public function storeContactList(Request $r): JsonResponse { $d=$r->validate(['name'=>'required|string|max:190','description'=>'nullable|string','channel'=>'nullable|string|max:40']); $id=DB::table('contact_lists')->insertGetId(['name'=>$d['name'],'slug'=>Str::slug($d['name']),'description'=>$d['description']??null,'channel'=>$d['channel']??'email','created_at'=>now(),'updated_at'=>now()]); return $this->success(['id'=>$id],201); } public function addMembers(Request $r, int $id): JsonResponse { $d=$r->validate(['members'=>'required|array','members.*.email'=>'nullable|email','members.*.phone'=>'nullable|string|max:60','members.*.customer_profile_id'=>'nullable|integer']); foreach($d['members'] as $m) DB::table('contact_list_members')->insert(['contact_list_id'=>$id,'customer_profile_id'=>$m['customer_profile_id']??null,'email'=>$m['email']??null,'phone'=>$m['phone']??null,'status'=>'active','created_at'=>now(),'updated_at'=>now()]); return $this->success(['message'=>'Members added.']); } }
